3.7 Crear variable respuesta


CĆ³digo
if (exists("atus_base") && "CLASACC" %in% names(atus_base)) {
  atus_modelo &lt;- atus_base |&gt;
    mutate(
      CLASACC_TXT = str_to_lower(as.character(CLASACC)),
      accidente_con_victimas = case_when(
        str_detect(CLASACC_TXT, "sĆ³lo daĆ±os") ~ "Solo daĆ±os",
        str_detect(CLASACC_TXT, "solo daĆ±os") ~ "Solo daĆ±os",
        str_detect(CLASACC_TXT, "daĆ±os") ~ "Solo daĆ±os",
        str_detect(CLASACC_TXT, "no fatal") ~ "Con vĆ­ctimas",
        str_detect(CLASACC_TXT, "fatal") ~ "Con vĆ­ctimas",
        TRUE ~ NA_character_
      )
    ) |&gt;
    filter(!is.na(accidente_con_victimas))

  table(atus_modelo$accidente_con_victimas)
}



