3.8 Preparar variables finales


CĆ³digo
if (exists("atus_modelo")) {
  atus_ml &lt;- atus_modelo |&gt;
    mutate(
      MES = as.factor(MES),
      ID_HORA = as.character(ID_HORA),
      DIASEMANA = as.factor(DIASEMANA),
      TIPACCID = as.factor(TIPACCID),
      CAUSAACCI = as.factor(CAUSAACCI),
      accidente_con_victimas = factor(accidente_con_victimas, levels = c("Con vĆ­ctimas", "Solo daĆ±os"))
    ) |&gt;
    select(accidente_con_victimas, MES, ID_HORA, DIASEMANA, TIPACCID, CAUSAACCI) |&gt;
    na.omit()

  data.frame(filas = nrow(atus_ml), columnas = ncol(atus_ml))
}


