4.3 Preparar variables


CĆ³digo
if (!is.null(atus_ml)) {
  atus_ml &lt;- atus_ml |&gt;
    mutate(
      ID_HORA_NUM = as.numeric(ID_HORA),
      MES_NUM = as.numeric(MES),
      MES_FACTOR = factor(sprintf("%02d", MES_NUM), levels = sprintf("%02d", 1:12)),
      accidente_con_victimas = factor(accidente_con_victimas, levels = c("Con vĆ­ctimas", "Solo daĆ±os"))
    )
}

6.4 Cargar y preparar datos


CĆ³digo
ruta_atus_ml &lt;- "datos/atus_ml_preparado.csv"
if (file.exists(ruta_atus_ml)) {
  atus_ml &lt;- read_csv(ruta_atus_ml, show_col_types = FALSE)
  set.seed(123)
  atus_knn_base &lt;- atus_ml |&gt; sample_n(min(12000, nrow(atus_ml))) |&gt;
    mutate(
      accidente_con_victimas = factor(accidente_con_victimas, levels = c("Con vĆ­ctimas", "Solo daĆ±os")),
      MES = as.factor(MES), ID_HORA = as.numeric(ID_HORA), DIASEMANA = as.factor(DIASEMANA), TIPACCID = as.factor(TIPACCID), CAUSAACCI = as.factor(CAUSAACCI)
    ) |&gt; na.omit()
}

